<script lang="ts">
  const html: string = "<h1>ContentsLink</h1>\n\n<p>A contents link is a single navigation link within a contents list, typically linking to a page or page section. Contents links are used in tables of contents, page outlines, and section navigation.</p>\n\n<p>This headless component uses an <code>&lt;a&gt;</code> element for native link semantics and keyboard navigation, with <code>aria-current</code> support for indicating the currently active section.</p>\n\n<h2>Implementation Notes</h2>\n\n<ul>\n<li>Uses native <code>&lt;a&gt;</code> element for inherent link behavior and keyboard support</li>\n<li><code>aria-current=\"true\"</code> indicates the currently active or visible section</li>\n<li><code>href</code> attribute links to the target page or section anchor</li>\n<li>Content is provided through child elements</li>\n</ul>\n\n<h2>Props</h2>\n\n<ul>\n<li><code>href</code>: string (required) -- the URL or anchor the link points to</li>\n<li><code>current</code>: boolean (default: false) -- whether this is the currently active section</li>\n<li><code>children</code>: slot (required) -- link text content</li>\n<li><code>...restProps</code>: Any additional HTML attributes</li>\n</ul>\n\n<h2>Usage</h2>\n\n<pre><code class=\"language-html\">&lt;ContentsNav label=\"Pages in this guide\"&gt;\n  &lt;ContentsList&gt;\n    &lt;ContentsListItem aria-current=\"page\"&gt;\n      What is type 2 diabetes?\n    &lt;/ContentsListItem&gt;\n    &lt;ContentsListItem&gt;\n      &lt;ContentsLink href=\"/conditions/type-2-diabetes/symptoms\"&gt;Symptoms&lt;/ContentsLink&gt;\n    &lt;/ContentsListItem&gt;\n    &lt;ContentsListItem&gt;\n      &lt;ContentsLink href=\"/conditions/type-2-diabetes/getting-diagnosed\"&gt;Getting diagnosed&lt;/ContentsLink&gt;\n    &lt;/ContentsListItem&gt;\n    &lt;ContentsListItem&gt;\n      &lt;ContentsLink href=\"/conditions/type-2-diabetes/treatment\"&gt;Treatment&lt;/ContentsLink&gt;\n    &lt;/ContentsListItem&gt;\n  &lt;/ContentsList&gt;\n&lt;/ContentsNav&gt;</code></pre>\n\n<h2>Keyboard Interactions</h2>\n\n<ul>\n<li>Tab: Focus the link</li>\n<li>Enter: Follow the link</li>\n<li>(All handled natively by <code>&lt;a&gt;</code> element)</li>\n</ul>\n\n<h2>ARIA</h2>\n\n<ul>\n<li>Implicit <code>link</code> role from <code>&lt;a&gt;</code> element</li>\n<li><code>aria-current=\"true\"</code> when the link corresponds to the currently visible section</li>\n</ul>\n\n<h2>When to Use</h2>\n\n<ul>\n<li>Use inside ContentsListItem to create a clickable link to a related page in the guide.</li>\n<li>Use concise, descriptive link text limited to approximately two lines.</li>\n</ul>\n\n<h2>When Not to Use</h2>\n\n<ul>\n<li>Do not use for the current page -- the current page should be plain text, not a link.</li>\n<li>Do not use outside of ContentsListItem -- use ActionLink or a standard anchor for standalone links.</li>\n</ul>\n\n<h2>Headless</h2>\n\n<p>This component provides a native <code>&lt;a&gt;</code> element with <code>aria-current</code> support for active section indication, with zero visual styling. The consumer is responsible for all CSS including text color, hover state, active/current indicator, and focus styling.</p>\n\n<h2>Styles</h2>\n\n<p>The consumer provides all CSS styling. The component renders with a <code>.contents-link</code> class for targeting. No default styles are included -- this is a fully headless component.</p>\n\n<h2>Testing</h2>\n\n<ul>\n<li>Verify the component renders an <code>&lt;a&gt;</code> element with class <code>contents-link</code></li>\n<li>Verify <code>href</code> attribute is applied</li>\n<li>Verify <code>aria-current</code> is set when <code>current</code> is true</li>\n<li>Verify keyboard interactions work correctly</li>\n<li>Verify pass-through attributes are applied</li>\n</ul>\n\n<h2>Advice</h2>\n\n<ul>\n<li><strong>Designers</strong>: Visually distinguish the current section link from others. Use indentation to show section hierarchy. Ensure sufficient contrast for link text.</li>\n<li><strong>Developers</strong>: Update <code>aria-current</code> dynamically as the user scrolls through sections for accurate screen reader announcements.</li>\n</ul>\n\n<h2>Composition</h2>\n\n<p>ContentsLink is used within ContentsListItem, which is part of ContentsList and ContentsNav.</p>\n\n<h2>Related components</h2>\n\n<ul>\n<li><code>contents-nav</code> — a contents navigation area</li>\n<li><code>contents-list</code> — an contents ordered list of contents list item components</li>\n<li><code>contents-list-item</code> — one contents list item</li>\n</ul>\n\n<h2>References</h2>\n\n<ul>\n<li><a href=\"https://developer.mozilla.org/en-US/docs/Web/HTML/Element/a\">MDN a element</a></li>\n</ul>";
  // BEGIN auto-generated component example consts
  const demoHtml: string = "<a class=\"contents-link\" href=\"#section\">Contents link</a>";
  const svelteSource: string = "// In your Svelte component:\nimport ContentsLink from \"lily-design-system-svelte-headless/components/ContentsLink/ContentsLink.svelte\";\n\n<ContentsLink>ContentsLink</ContentsLink>\n";
  // END auto-generated component example consts
